{"name": "rss_polling", "kind": "polling", "polling_interval": "60s", "description": "轮询 RSS feed，使用 cursor（基于 entry id/link）记录已处理条目，防止重复触发。订阅地址通过配置或参数传入。", "code": """"
RSS 轮询函数
- 通过 cursor 文件记录已处理条目的 id/link，避免重复
- 每次运行只返回新条目

订阅地址需要先设置环境变量 RSS_URL，或通过 kwargs 传入 url。
"""

import json
import os
import time
import hashlib
import logging
from urllib.request import urlopen, Request
from xml.etree import ElementTree as ET

logger = logging.getLogger(__name__)

# cursor 文件路径，可被持久化
CURSOR_FILE = os.path.join(os.path.dirname(__file__), '.rss_cursor.json')


def _get_cursor():
    """读取已处理的条目 ID 集合"""
    if not os.path.exists(CURSOR_FILE):
        return set()
    try:
        with open(CURSOR_FILE, 'r') as f:
            data = json.load(f)
            return set(data.get('processed_ids', []))
    except (json.JSONDecodeError, IOError):
        return set()


def _save_cursor(processed_ids: set):
    """保存已处理的条目 ID 集合"""
    with open(CURSOR_FILE, 'w') as f:
        json.dump({'processed_ids': list(processed_ids)}, f)


def _extract_entry_id(entry):
    """从 RSS 条目中提取唯一 ID。优先用 id/guid，其次用 link。"""
    for child in entry:
        tag = child.tag.split('}')[-1]  # 去掉 namespace
        if tag in ('guid', 'id'):
            return child.text.strip()
    # 回退：用 link + title 做 hash
    link = ''
    title = ''
    for child in entry:
        tag = child.tag.split('}')[-1]
        if tag == 'link':
            link = child.text.strip() if child.text else (child.get('href') or '')
        elif tag == 'title':
            title = child.text or ''
    if link:
        return hashlib.sha256(f'{link}:{title}'.encode()).hexdigest()
    return None


def _fetch_and_parse(url: str, timeout: int = 15):
    """获取并解析 RSS feed，返回条目列表"""
    req = Request(url, headers={
        'User-Agent': 'Forgify-RSS-Poller/1.0',
        'Accept': 'application/rss+xml, application/xml, text/xml',
    })
    with urlopen(req, timeout=timeout) as resp:
        raw = resp.read()

    root = ET.fromstring(raw)

    # 兼容 RSS 2.0 和 Atom
    entries = []

    # RSS 2.0: /rss/channel/item
    channel = root.find('channel')
    if channel is not None:
        entries = channel.findall('item')
    else:
        # Atom: /feed/entry
        entries = root.findall('{http://www.w3.org/2005/Atom}entry')

    return entries


def main(**kwargs):
    """主入口

    Args:
        url (str, optional): RSS 订阅地址。默认从环境变量 RSS_URL 读取。
    """
    url = kwargs.get('url') or os.environ.get('RSS_URL')
    if not url:
        logger.warning('未设置 RSS 订阅地址。请设置环境变量 RSS_URL 或传入 url 参数。')
        return {'status': 'skipped', 'reason': 'no_url', 'new_entries': []}

    # 读取 cursor
    processed = _get_cursor()
    logger.info('当前已处理条目数: %d', len(processed))

    # 获取 feed
    entries = _fetch_and_parse(url)
    logger.info('获取到 %d 条条目', len(entries))

    new_entries = []
    for entry in entries:
        eid = _extract_entry_id(entry)
        if eid is None:
            continue
        if eid in processed:
            continue
        # 提取基本信息
        info = {}
        for child in entry:
            tag = child.tag.split('}')[-1]
            if tag == 'title':
                info['title'] = child.text
            elif tag == 'link':
                info['link'] = child.text.strip() if child.text else (child.get('href') or '')
            elif tag in ('pubDate', 'published', 'updated'):
                info['published'] = child.text
            elif tag in ('description', 'summary', 'content'):
                info['summary'] = child.text[:200] if child.text else ''
        info['_id'] = eid
        new_entries.append(info)
        processed.add(eid)

    # 保存 cursor
    _save_cursor(processed)
    logger.info('新条目数: %d', len(new_entries))

    return {
        'status': 'ok',
        'new_count': len(new_entries),
        'new_entries': new_entries,
    }
"}

{"name": "rss_poller", "kind": "polling", "polling_interval": "60s", "description": "Polling RSS function with cursor-based dedup. Pulls RSS feed, filters new items since cursor, updates cursor on completion. Subscriber URL to be configured later.", "code": """"
RSS Polling Function
- Polls a configured RSS feed URL every 60 seconds
- Uses cursor (stored in context.state) to track the latest processed item's timestamp/id
- Only yields items newer than cursor, preventing duplicate work
- Updates cursor after each successful poll

Usage:
  Set the RSS feed URL via context.state['feed_url'] = '...'
"""

import feedparser
import time
from datetime import datetime, timezone
from typing import Optional


def run(context):
    """
    Poll the configured RSS feed, yield new items since cursor.

    Expected context.state keys:
      - feed_url (str): the RSS feed URL to poll
      - cursor (str | None): ISO-8601 timestamp of the latest processed item,
        or an item GUID. Used to filter out old items.
      - cursor_type (str): 'timestamp' (default) or 'guid'

    Returns:
      A dict with:
        - new_items: list of new entry dicts (title, link, published, summary, guid)
        - count: number of new items
        - cursor_updated: whether cursor was advanced
    """
    state = context.state or {}
    feed_url = state.get('feed_url', '')
    cursor = state.get('cursor', None)
    cursor_type = state.get('cursor_type', 'timestamp')

    if not feed_url:
        return {
            'new_items': [],
            'count': 0,
            'cursor_updated': False,
            'error': 'feed_url not set in context.state',
        }

    # Parse the RSS feed
    parsed = feedparser.parse(feed_url)

    if parsed.bozo and not parsed.entries:
        return {
            'new_items': [],
            'count': 0,
            'cursor_updated': False,
            'error': f'Failed to parse feed: {parsed.bozo_exception}',
        }

    new_items = []
    latest_cursor = cursor

    for entry in parsed.entries:
        # Determine item identifier for comparison
        if cursor_type == 'guid':
            item_id = entry.get('id', entry.get('link', ''))
        else:
            # Use published_parsed or updated_parsed as timestamp
            pub_time = None
            if hasattr(entry, 'published_parsed') and entry.published_parsed:
                pub_time = time.mktime(entry.published_parsed)
            elif hasattr(entry, 'updated_parsed') and entry.updated_parsed:
                pub_time = time.mktime(entry.updated_parsed)
            else:
                # Fallback to current time if no timestamp available
                pub_time = time.time()

            item_id = datetime.fromtimestamp(pub_time, tz=timezone.utc).isoformat()

        # If cursor exists, skip items older than or equal to cursor
        if cursor:
            if cursor_type == 'guid':
                if item_id == cursor:
                    continue  # already processed this item
            else:
                # timestamp comparison
                if item_id <= cursor:
                    continue  # already processed up to this point

        # This is a new item
        new_items.append({
            'title': entry.get('title', ''),
            'link': entry.get('link', ''),
            'published': entry.get('published', ''),
            'summary': entry.get('summary', ''),
            'guid': entry.get('id', entry.get('link', '')),
            'cursor_value': item_id,
        })

        # Track the latest cursor value
        if cursor_type == 'guid':
            # For GUID mode, we just track the last GUID (simplistic dedup)
            latest_cursor = item_id
        else:
            # For timestamp mode, keep the latest timestamp (items are usually sorted)
            if latest_cursor is None or item_id > latest_cursor:
                latest_cursor = item_id

    # Update cursor in context state
    if new_items and latest_cursor:
        # Only update if we advanced beyond the previous cursor
        if cursor is None or latest_cursor > cursor:
            context.state['cursor'] = latest_cursor
            cursor_updated = True
        else:
            cursor_updated = False
    else:
        cursor_updated = False

    # If no new items but feed was parsed, we still mark as processed
    if not new_items and not cursor and parsed.entries:
        # First run with no cursor — set cursor to latest item to avoid reprocessing
        if cursor_type != 'guid' and parsed.entries:
            last_entry = parsed.entries[0]  # feedparser usually returns newest first
            pub_time = None
            if hasattr(last_entry, 'published_parsed') and last_entry.published_parsed:
                pub_time = time.mktime(last_entry.published_parsed)
            elif hasattr(last_entry, 'updated_parsed') and last_entry.updated_parsed:
                pub_time = time.mktime(last_entry.updated_parsed)
            if pub_time:
                context.state['cursor'] = datetime.fromtimestamp(pub_time, tz=timezone.utc).isoformat()
                cursor_updated = True

    return {
        'new_items': new_items,
        'count': len(new_items),
        'cursor_updated': cursor_updated,
        'feed_title': parsed.feed.get('title', ''),
    }
"}

{"name": "rss_poller", "kind": "polling", "polling_interval": "60s", "description": "Polling RSS 订阅函数，支持 cursor 防重复触发。通过环境变量 RSS_URL 配置订阅地址，自动记录最新条目标识，每次只返回增量新条目。", "code": """"
RSS Polling 订阅函数
- 每隔 60 秒自动拉取 RSS
- 使用 cursor 记录上次最新条目的 ID，防止重复触发
- 通过环境变量 RSS_URL 配置订阅地址
- 支持多个 URL（逗号分隔）
"""

import feedparser
import json
import os
from datetime import datetime, timezone
from pathlib import Path

# cursor 持久化文件路径（存在函数同目录，保留状态）
CURSOR_FILE = Path(__file__).parent / ".rss_cursor.json"


def _load_cursor() -> dict:
    """加载所有订阅的 cursor 状态"""
    if CURSOR_FILE.exists():
        try:
            return json.loads(CURSOR_FILE.read_text(encoding="utf-8"))
        except (json.JSONDecodeError, OSError):
            return {}
    return {}


def _save_cursor(cursor: dict):
    """持久化 cursor 状态"""
    CURSOR_FILE.parent.mkdir(parents=True, exist_ok=True)
    CURSOR_FILE.write_text(json.dumps(cursor, ensure_ascii=False, indent=2), encoding="utf-8")


def _parse_entry_id(entry) -> str:
    """提取条目标识，优先级：id > link > title"""
    return entry.get("id") or entry.get("link") or entry.get("title", "")


def main():
    """
    Polling 入口，由 Forgify 系统定时调度（60s）。
    返回新增条目列表。
    """
    rss_urls_str = os.environ.get("RSS_URL", "").strip()
    if not rss_urls_str:
        return {
            "status": "idle",
            "message": "未配置 RSS_URL 环境变量，请设置订阅地址",
            "new_entries": [],
        }

    # 支持多个订阅地址（逗号/分号分隔）
    urls = [u.strip() for u in rss_urls_str.replace(";", ",").split(",") if u.strip()]
    cursor = _load_cursor()
    all_new_entries = []
    results = []

    for url in urls:
        try:
            feed = feedparser.parse(url)

            if feed.bozo and not feed.entries:
                results.append({"url": url, "error": f"RSS 解析失败: {feed.bozo_exception}"})
                continue

            if not feed.entries:
                results.append({"url": url, "new_count": 0, "message": "订阅源暂无条目"})
                continue

            # 获取该订阅源上次的 cursor
            last_entry_id = cursor.get(url, "")

            new_entries = []
            found_last = False

            for entry in feed.entries:
                eid = _parse_entry_id(entry)
                if not eid:
                    continue

                # 如果遇到了上次记录的 ID，说明之后（更旧）的条目都已处理过
                if eid == last_entry_id:
                    found_last = True
                    break

                new_entries.append(
                    {
                        "id": eid,
                        "title": entry.get("title", ""),
                        "link": entry.get("link", ""),
                        "published": entry.get("published", ""),
                        "published_parsed": (
                            datetime(*entry.published_parsed[:6], tzinfo=timezone.utc).isoformat()
                            if entry.get("published_parsed")
                            else ""
                        ),
                        "summary": (entry.get("summary") or entry.get("description") or "")[
                            :500
                        ],
                    }
                )

            # 如果有新条目，更新 cursor 为最新条目的 ID
            if new_entries:
                cursor[url] = new_entries[0]["id"]
                all_new_entries.extend(new_entries)

            results.append(
                {
                    "url": url,
                    "new_count": len(new_entries),
                    "cursor": cursor.get(url, ""),
                }
            )

        except Exception as e:
            results.append({"url": url, "error": str(e)})

    # 持久化 cursor（只要有变化就保存）
    _save_cursor(cursor)

    return {
        "status": "ok",
        "total_new": len(all_new_entries),
        "new_entries": all_new_entries,
        "results": results,
    }
"}
